package pe.org.camaracomercioica.protestos.service;
import lombok.RequiredArgsConstructor; import org.springframework.security.authentication.*; import org.springframework.security.core.AuthenticationException; import org.springframework.stereotype.Service; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.exception.BadRequestException; import pe.org.camaracomercioica.protestos.repository.UsuarioRepository; import pe.org.camaracomercioica.protestos.security.JwtService;
@Service @RequiredArgsConstructor public class AuthService {private final AuthenticationManager authenticationManager;private final UsuarioRepository users;private final JwtService jwt;public LoginResponse login(LoginRequest r){try{authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(r.email(),r.password()));}catch(AuthenticationException e){throw new BadRequestException("Credenciales inválidas");}return jwt.issue(users.findByEmailIgnoreCase(r.email()).orElseThrow(()->new BadRequestException("Credenciales inválidas")));}}
